mapper.select:
SELECT
    (SELECT COUNT(*) FROM course c WHERE c.teacher_id = #{teacherId})
        AS course_count,
    (SELECT COUNT(*)
     FROM assignment asn
     WHERE asn.course_id IN (
         SELECT c2.id FROM course c2 WHERE c2.teacher_id = #{teacherId}
     ))  AS assignment_count,
    (SELECT COUNT(*)
     FROM submission sub
     WHERE sub.assignment_id IN (
         SELECT asn2.id FROM assignment asn2
         WHERE asn2.course_id IN (
             SELECT c3.id FROM course c3 WHERE c3.teacher_id = #{teacherId}
         )
     ) AND sub.id NOT IN (
         SELECT g.submission_id FROM grade g
     ))  AS pending_grading,
    (SELECT COUNT(DISTINCT cs.student_id)
     FROM course_student cs
     WHERE cs.course_id IN (
         SELECT c4.id FROM course c4 WHERE c4.teacher_id = #{teacherId}
     ))  AS total_students
